defmodule SessionPlug do
  @moduledoc """
  A Plug for integrating SessionManager into a Phoenix/Plug pipeline.
  Loads session from cookie on request and saves it on response.
  """

  import Plug.Conn

  @session_cookie "_app_session"

  def init(opts), do: opts

  def call(conn, _opts) do
    cookie_value = fetch_session_cookie(conn)
    session = SessionManager.load_or_create(cookie_value)

    conn
    |> assign(:session, session)
    |> register_before_send(&save_session/1)
  end

  defp fetch_session_cookie(conn) do
    conn = fetch_cookies(conn)
    Map.get(conn.cookies, @session_cookie)
  end

  defp save_session(conn) do
    case conn.assigns[:session] do
      nil ->
        conn

      session ->
        serialized = SessionManager.serialize(session)
        opts = SessionManager.cookie_options()

        put_resp_cookie(conn, @session_cookie, serialized,
          max_age: opts[:max_age],
          http_only: opts[:http_only],
          secure: opts[:secure],
          same_site: opts[:same_site],
          path: opts[:path]
        )
    end
  end
end

